import React, { useEffect, useState, useMemo } from "react";
import axios from "axios";
import { Bar, Pie } from "react-chartjs-2";
import "./AdminDashboard.css";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  ArcElement,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(CategoryScale, LinearScale, BarElement, ArcElement, Tooltip, Legend);

const AdminDashboard = () => {
  const [predictions, setPredictions] = useState([]);
  const [dashboard, setDashboard] = useState({});

  // ================= FETCH API =================
  useEffect(() => {
    const fetchData = async () => {
      try {
        const res = await axios.get("http://localhost:5000/admin/dashboard");

        console.log("API RESPONSE:", res.data);

        setPredictions(res.data.predictions || []);
        setDashboard(res.data || {});
      } catch (err) {
        console.log("Error:", err);
      }
    };

    fetchData();

    const interval = setInterval(fetchData, 5000);
    return () => clearInterval(interval);
  }, []);

  // ================= EXTRACT SALARIES =================
  const salaries = useMemo(() => {
    return (Array.isArray(predictions) ? predictions : [])
      .map((p) => Number(p.predictedSalary))
      .filter((s) => !isNaN(s) && s > 0);
  }, [predictions]);

  // ================= SALARY BUCKETS (PER ANNUM) =================
  const salaryBuckets = useMemo(() => {
    const buckets = {
      "2-4L": 0,
      "4-6L": 0,
      "6-8L": 0,
      "8-10L": 0,
      "10L+": 0,
    };

    salaries.forEach((s) => {
      if (s >= 200000 && s < 400000) buckets["2-4L"]++;
      else if (s >= 400000 && s < 600000) buckets["4-6L"]++;
      else if (s >= 600000 && s < 800000) buckets["6-8L"]++;
      else if (s >= 800000 && s < 1000000) buckets["8-10L"]++;
      else if (s >= 1000000) buckets["10L+"]++;
    });

    return buckets;
  }, [salaries]);

  return (
    <div className="admin-view">

      {/* ================= STATS ================= */}
      <section className="stats-container">

        <div className="stat-box">
          <h3>Avg Salary</h3>
          <p>₹{dashboard.avgSalary?.toLocaleString() || 0}</p>
        </div>

        <div className="stat-box">
          <h3>Highest Salary</h3>
          <p>₹{dashboard.highestSalary?.toLocaleString() || 0}</p>
        </div>

        <div className="stat-box">
          <h3>Lowest Salary</h3>
          <p>₹{dashboard.lowestSalary?.toLocaleString() || 0}</p>
        </div>

        <div className="stat-box">
          <h3>Total Users</h3>
          <p>{dashboard.totalUsers || 0}</p>
        </div>

      </section>

      {/* ================= BAR CHART ================= */}
      <section className="chart-card">
        <h2>Salary Distribution (Per Annum)</h2>

        <div style={{ height: "300px" }}>
          <Bar
            data={{
              labels: Object.keys(salaryBuckets),
              datasets: [
                {
                  label: "Number of Users",
                  data: Object.values(salaryBuckets),
                  backgroundColor: "#3b82f6",
                },
              ],
            }}
            options={{ responsive: true, maintainAspectRatio: false }}
          />
        </div>
      </section>

      {/* ================= PIE CHART ================= */}
      <section className="chart-card">
        <h2>User Salary Distribution</h2>

        <div style={{ height: "300px" }}>
          <Pie
            data={{
              labels: Object.keys(salaryBuckets),
              datasets: [
                {
                  data: Object.values(salaryBuckets),
                  backgroundColor: [
                    "#6366f1",
                    "#f59e0b",
                    "#10b981",
                    "#ef4444",
                    "#06b6d4",
                  ],
                },
              ],
            }}
            options={{ responsive: true, maintainAspectRatio: false }}
          />
        </div>
      </section>

      {/* ================= TABLE ================= */}
      <section className="table-container">
        <h2>Recent Predictions</h2>

        <table>
          <thead>
            <tr>
              <th>Email</th>
              <th>Role</th>
              <th>Location</th>
              <th>Predicted Salary</th>
            </tr>
          </thead>

          <tbody>
            {predictions.slice(-5).reverse().map((p, i) => (
              <tr key={i}>
                <td>{p.email}</td>
                <td>{p.role}</td>
                <td>{p.location}</td>
                <td>₹{Number(p.predictedSalary || 0).toLocaleString()}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </section>

    </div>
  );
};

export default AdminDashboard;
